using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // HasIndex removed — throws in EF Core 9 Cosmos. Manage indexes via Azure Portal / Bicep.
        modelBuilder.Entity<Product>().ToContainer("Products");

        // Preserve "Discriminator" property name used by existing 500K documents.
        // EF Core 9 defaults to "$type"; without this, queries won't match existing data.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // Preserve the EF Core 8 compound id format ("Product|123") in existing documents.
        // EF Core 9 defaults to bare key ("123"), which breaks FindAsync on old documents.
        modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

