using System.Linq;
using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // Sync I/O throws in EF Core 9 Cosmos — all query/save methods must be async.
    async System.Threading.Tasks.Task FindProducts(ProductContext ctx)
    {
        // This raw SQL is safe: c.Discriminator still works because we configured
        // HasDiscriminator<string>("Discriminator") to preserve the EF Core 8 property name.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

